import { useState, useEffect, useRef } from "react";
import "../styles/Stats.css";

export default function Stats() {
  const stats = [
    { label: "Projects Completed", value: 500 },
    { label: "Clients Served", value: 300 },
    { label: "Years of Experience", value: 2 },
    { label: "Client Satisfaction", value: 100, suffix: "%" },
    { label: "Team Members", value: 25 },
    { label: "24/7 Customer Support", value: "✔️", isText: true },
  ];

  const [animatedValues, setAnimatedValues] = useState(stats.map(() => 0));
  const [inView, setInView] = useState(false);
  const statsSectionRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setInView(true);
          }
        });
      },
      {
        threshold: 0.5, // Trigger when 50% of the section is visible
      }
    );

    if (statsSectionRef.current) {
      observer.observe(statsSectionRef.current);
    }

    return () => {
      if (statsSectionRef.current) {
        observer.unobserve(statsSectionRef.current);
      }
    };
  }, []);

  useEffect(() => {
    if (!inView) return;

    const interval = setInterval(() => {
      setAnimatedValues((prevValues) =>
        prevValues.map((value, index) => {
          const target = stats[index].value;
          if (value < target) {
            return Math.min(value + Math.ceil(target / 50), target);
          }
          return value;
        })
      );
    }, 30);

    return () => clearInterval(interval);
  }, [inView]);

  return (
    <section ref={statsSectionRef} className="stats-section">
      {stats.map((stat, index) => (
        <div key={index} className="stat-item">
          <h4>{animatedValues[index]}+</h4>
          <p>{stat.label}</p>
        </div>
      ))}
    </section>
  );
}
